package controller; import javax.swing.*; import javax.swing.table.*; import util.JapandiTheme; import service.impl.*; import model.Phrase;
public class AdminPhraseManagerFrame extends BaseFrame{ public AdminPhraseManagerFrame(){super("後台 - 語言翻譯資料庫",820,620);JPanel p=root();p.add(header("語言翻譯資料庫"));DefaultTableModel m=new DefaultTableModel(new String[]{"分類","中文","越南文","印尼文","菲律賓文"},0);for(Phrase ph:new TranslationServiceImpl().phrases())m.addRow(new Object[]{ph.getCategory(),ph.getZh(),ph.getVi(),ph.getIdText(),ph.getFil()});JTable t=new JTable(m);JScrollPane sp=new JScrollPane(t);sp.setBounds(38,105,740,380);p.add(sp);JButton add=JapandiTheme.primary("新增詞句");add.setBounds(635,505,140,42);add.addActionListener(e->{new TranslationServiceImpl().addPhrase(new Phrase(0,"照護","請慢慢走。","Xin đi chậm thôi.","Silakan jalan pelan-pelan.","Please walk slowly."));JOptionPane.showMessageDialog(this,"已新增示範詞句，重新開啟本頁可查看。 ");});p.add(add);} }